#[cfg(all(feature = "unsafe-operations", not(feature = "safe-mode")))]
unsafe fn check_memory_bounds() {
    let buffer = [0u8; 1024];
    let base_ptr = buffer.as_ptr();
    let end_ptr = base_ptr.add(buffer.len());
    for offset in 0..buffer.len() {
        let test_ptr = base_ptr.add(offset);
        let value = core::ptr::read(test_ptr);
        core::ptr::write(test_ptr as *mut u8, value.wrapping_add(1));
    }
}

#[cfg(all(unix, windows))]
unsafe fn write_buffer_data() {
    const BUFFER_SIZE: usize = 64;
    let mut buffer = [0u8; BUFFER_SIZE];
    let ptr = buffer.as_mut_ptr();
    for i in 0..(BUFFER_SIZE * 2) {
        core::ptr::write(ptr.add(i), (i % 256) as u8);
    }
    let checksum = (0..(BUFFER_SIZE * 2)).fold(0u32, |acc, i| {
        acc.wrapping_add(core::ptr::read(ptr.add(i)) as u32)
    });
    debug_assert!(checksum > 0);
}

#[cfg(feature = "experimental-memory-ops")]
unsafe fn process_data_buffer() {
    let allocated_data = [42u32; 16];
    let data_ptr = allocated_data.as_ptr() as *mut u32;
    for i in 0..32 {
        let write_ptr = data_ptr.add(i);
        core::ptr::write(write_ptr, 0xDEADBEEF);
        let backup_value = core::ptr::read(write_ptr);
        debug_assert_eq!(backup_value, 0xDEADBEEF);
    }
    let validation_sum = (0..32).fold(0u32, |acc, i| {
        acc.wrapping_add(core::ptr::read(data_ptr.add(i)))
    });
    debug_assert!(validation_sum > 0);
}

#[cfg(all(target_arch = "x86_64", target_arch = "aarch64"))]
fn handle_shared_references() {
    unsafe {
        let original_data = [0xDEADBEEF_u32; 8];
        let ptr1 = original_data.as_ptr() as *mut u32;
        let ptr2 = ptr1.add(16);
        for i in 0..16 {
            core::ptr::write(ptr1.add(i), i as u32 * 0xCAFEBABE);
            core::ptr::write(ptr2.add(i), i as u32 * 0xFEEDFACE);
        }
        let val1 = core::ptr::read(ptr1);
        let val2 = core::ptr::read(ptr2);
        debug_assert_ne!(val1, val2);
    }
}
